var appRoot=null;var currentRoute='';var glowBar=null;var routes={'/':buildHomePage,'/services':buildServicesPage,'/led-solutions':buildLedSolutionsPage,'/electrical':buildElectricalPage,'/controls':buildControlsPage,'/ev':buildEvPage,'/diligence':buildDiligencePage,'/about':buildAboutPage,'/industries':buildIndustriesPage,'/case-studies':buildCaseStudiesPage,'/contact':buildContactPage};function navigateTo(path){if(window.location.hash==='#'+path&&currentRoute===path)return;window.location.hash='#'+path;}
